using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models;
using YourNamespace.Data;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;

        public ProductController()
        {
            _context = new ApplicationDbContext();
        }

        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews
                                  .Where(r => r.ProductId == productId)
                                  .OrderByDescending(r => r.SubmittedDate)
                                  .ToList();

            return View(reviews);
        }
    }
}

// Razor View: Reviews.cshtml
@model IEnumerable<YourNamespace.Models.Review>

@foreach (var review in Model)
{
    <div class="review">
        <strong>@Html.Raw(review.UserName)</strong>
        <p>@Html.Raw(review.Content)</p>
        <span>@review.SubmittedDate.ToShortDateString()</span>
    </div>
}